{
  "sentences": [
    {
      "text": "喂，請問是診所嗎？",
      "pinyin": "Wèi, qǐngwèn shì zhěnsuǒ ma?",
      "pinyin_numeric": "wei4, qing3wen4 shi4 zhen3suo3 ma0",
      "translation_en": "Hello, is this the clinic?",
      "translation_ko": "여보세요, 진료소 맞습니까?"
    },
    {
      "text": "不好意思，我打錯了。",
      "pinyin": "Bù hǎo yìsi, wǒ dǎ cuò le.",
      "pinyin_numeric": "bu4 hao3 yi4si0, wo3 da3 cuo4 le0",
      "translation_en": "Sorry, I dialed the wrong number.",
      "translation_ko": "죄송합니다, 잘못 걸었습니다."
    },
    {
      "text": "請問你們今天有營業嗎？",
      "pinyin": "Qǐngwèn nǐmen jīntiān yǒu yíngyè ma?",
      "pinyin_numeric": "qing3wen4 ni3men0 jin1tian1 you3 ying2ye4 ma0",
      "translation_en": "Excuse me, are you open today?",
      "translation_ko": "실례합니다, 오늘 영업하나요?"
    },
    {
      "text": "我想預約明天下午看診。",
      "pinyin": "Wǒ xiǎng yùyuē míngtiān xiàwǔ kànzhěn.",
      "pinyin_numeric": "wo3 xiang3 yu4yue1 ming2tian1 xia4wu3 kan4zhen3",
      "translation_en": "I'd like to make an appointment for tomorrow afternoon.",
      "translation_ko": "내일 오후에 진료 예약을 하고 싶습니다."
    },
    {
      "text": "喂，我找王小姐，她在嗎？",
      "pinyin": "Wèi, wǒ zhǎo Wáng xiǎojiě, tā zài ma?",
      "pinyin_numeric": "wei4, wo3 zhao3 Wang2 xiao3jie3, ta1 zai4 ma0",
      "translation_en": "Hello, I'm looking for Miss Wang. Is she there?",
      "translation_ko": "여보세요, 왕 씨를 찾는데요, 계신가요?"
    },
    {
      "text": "對不起，我打錯了，沒關係。",
      "pinyin": "Duìbuqǐ, wǒ dǎ cuò le, méi guānxi.",
      "pinyin_numeric": "dui4bu5qi3, wo3 da3 cuo4 le0, mei2 guan1xi0",
      "translation_en": "Sorry, I dialed the wrong number. It's okay.",
      "translation_ko": "죄송합니다, 잘못 걸었어요. 괜찮습니다."
    },
    {
      "text": "請問你們有外送服務嗎？",
      "pinyin": "Qǐngwèn nǐmen yǒu wàisòng fúwù ma?",
      "pinyin_numeric": "qing3wen4 ni3men0 you3 wai4song4 fu2wu4 ma0",
      "translation_en": "Excuse me, do you offer delivery service?",
      "translation_ko": "실례합니다, 배달 서비스가 있나요?"
    },
    {
      "text": "喂，我打錯了，不好意思打擾了。",
      "pinyin": "Wèi, wǒ dǎ cuò le, bù hǎo yìsi dǎrǎo le.",
      "pinyin_numeric": "wei4, wo3 da3 cuo4 le0, bu4 hao3 yi4si0 da3rao3 le0",
      "translation_en": "Hello, I dialed the wrong number. Sorry to bother you.",
      "translation_ko": "여보세요, 잘못 걸었어요. 방해해서 죄송합니다."
    },
    {
      "text": "我想訂位，今天晚上有座位嗎？",
      "pinyin": "Wǒ xiǎng dìngwèi, jīntiān wǎnshàng yǒu zuòwèi ma?",
      "pinyin_numeric": "wo3 xiang3 ding4wei4, jin1tian1 wan3shang4 you3 zuo4wei4 ma0",
      "translation_en": "I'd like to make a reservation. Do you have seats tonight?",
      "translation_ko": "예약하고 싶은데요, 오늘 저녁에 자리가 있나요?"
    },
    {
      "text": "不好意思，我打錯了，再見。",
      "pinyin": "Bù hǎo yìsi, wǒ dǎ cuò le, zàijiàn.",
      "pinyin_numeric": "bu4 hao3 yi4si0, wo3 da3 cuo4 le0, zai4jian4",
      "translation_en": "Sorry, I dialed the wrong number. Goodbye.",
      "translation_ko": "죄송합니다, 잘못 걸었어요. 안녕히 계세요."
    }
  ]
}
